const srcC:Record<string,string>={X:"#000",Facebook:"#1877f2",Instagram:"#e4405f",TikTok:"#00b4a6",YouTube:"#f00","Periódico":"#377eb8",Internet:"#e41a1b",Radio:"#ffcd00","Televisión":"#4eaf4a",Revista:"#7f7f7f"};
const VS=["Facebook","Instagram","TikTok","X","YouTube"];
const VM=["Internet","Periódico","Radio","Revista","Televisión"];

/* ═══════ TYPES ═══════ */
interface SocialRow{Fecha:string;Fuente:string;Autor:string;Sentimiento:string;Alcance:number;Likes:number;Comentarios:number;Compartidos:number;Contenido:string;Link:string;Seguidores:number;AVE:number;Hora:number}
interface MediaRow{Titulo:string;Texto:string;Autor:string;Fecha:string;Medio:string;TipoMedio:string;Sentimiento:string;Alcance:number;Tier:string;Costo:number;Link:string;TipoNota:string;Estado:string}
interface Brand{name:string;primaryColor:string;secondaryColor:string;accentColor:string;positiveColor:string;negativeColor:string;neutralColor:string;chartColors:string[];titleFont:string;bodyFont:string;mediaColors:Record<string,string>;tierColors:Record<string,string>;top5MedColor:string;bannerPrimary:string;bannerSecondary:string;titleTextColor:string;aiBlockColor:string}
interface TrendRow{date:string;total:number;Positivo:number;Negativo:number;Neutro:number;[k:string]:string|number}
interface FuenteRow{fuente:string;Positivo:number;Negativo:number;Neutro:number;total:number}
interface KpiFuente{fuente:string;menciones:number;interacciones:number;impresiones:number;lideres:number;costo:number}
interface Top5Item{nombre:string;valor:number;link:string;fuente:string;titulo:string}
interface PData{
  dataType:"social"|"media"|"fusionado";totalMenciones:number;totalAlcance:number;totalInteracciones:number;autoresUnicos:number;totalCosto:number;
  sentCounts:{Positivo:number;Negativo:number;Neutro:number};sentNeto:number;
  trendData:TrendRow[];fuenteData:FuenteRow[];kpiByFuente:KpiFuente[];
  topPositivas:{autor:string;contenido:string;link:string;fuente:string;alcance:number}[];
  topNegativas:{autor:string;contenido:string;link:string;fuente:string;alcance:number}[];
  rawRows:(SocialRow|MediaRow)[];
  top5AlcGeneral:Top5Item[];top5CostGeneral:Top5Item[];
  top5AlcPorFuente:Record<string,Top5Item[]>;top5CostPorFuente:Record<string,Top5Item[]>;
  hourData:{hora:number;total:number}[];
  tierData:{name:string;value:number}[];tipoNotaData:{name:string;value:number}[];estadoData:{name:string;value:number}[];top5Medios:{nombre:string;total:number}[];
}

/* ═══════ PROCESSING ═══════ */
function processSocial(rows:SocialRow[]):PData{
  const f=rows.filter(r=>VS.includes(r.Fuente));const n=f.length;
  const alc=f.reduce((s,r)=>s+(r.Alcance||0),0);
  const inter=f.reduce((s,r)=>s+(r.Likes||0)+(r.Comentarios||0)+(r.Compartidos||0),0);
  const uniq=new Set(f.map(r=>r.Autor)).size;
  const costT=f.reduce((s,r)=>s+(r.AVE||0),0);
  const sc={Positivo:0,Negativo:0,Neutro:0};
  f.forEach(r=>{if(r.Sentimiento==="Positivo")sc.Positivo++;if(r.Sentimiento==="Negativo")sc.Negativo++;if(r.Sentimiento==="Neutro")sc.Neutro++});
  const sn=n>0?((sc.Positivo-sc.Negativo)/n)*100:0;
  const dm:Record<string,TrendRow>={};
  f.forEach(r=>{const d=r.Fecha?.substring(0,10);if(!d)return;if(!dm[d]){const e:TrendRow={date:d,total:0,Positivo:0,Negativo:0,Neutro:0};VS.forEach(s=>{e[s]=0});dm[d]=e}dm[d].total++;if(r.Sentimiento==="Positivo"||r.Sentimiento==="Negativo"||r.Sentimiento==="Neutro")(dm[d][r.Sentimiento] as number)++;if(VS.includes(r.Fuente))(dm[d][r.Fuente] as number)++});
  const td=Object.values(dm).sort((a,b)=>a.date.localeCompare(b.date));
  const fm:Record<string,FuenteRow>={};
  f.forEach(r=>{const k=r.Fuente;if(!fm[k])fm[k]={fuente:k,Positivo:0,Negativo:0,Neutro:0,total:0};fm[k].total++;if(r.Sentimiento==="Positivo")fm[k].Positivo++;if(r.Sentimiento==="Negativo")fm[k].Negativo++;if(r.Sentimiento==="Neutro")fm[k].Neutro++});
  const fd=Object.values(fm).sort((a,b)=>{const ia=VS.indexOf(a.fuente);const ib=VS.indexOf(b.fuente);return ia-ib});
  const km:Record<string,{fuente:string;menciones:number;interacciones:number;impresiones:number;autores:Set<string>;costo:number}>={};
  f.forEach(r=>{const k=r.Fuente;if(!km[k])km[k]={fuente:k,menciones:0,interacciones:0,impresiones:0,autores:new Set(),costo:0};km[k].menciones++;km[k].interacciones+=(r.Likes||0)+(r.Comentarios||0)+(r.Compartidos||0);km[k].impresiones+=r.Alcance||0;km[k].autores.add(r.Autor);km[k].costo+=r.AVE||0});
  const kf=Object.values(km).map(k=>({fuente:k.fuente,menciones:k.menciones,interacciones:k.interacciones,impresiones:k.impresiones,lideres:k.autores.size,costo:k.costo})).sort((a,b)=>{const ia=VS.indexOf(a.fuente);const ib=VS.indexOf(b.fuente);return ia-ib});
  const seen1=new Set<string>();const tp=f.filter(r=>r.Sentimiento==="Positivo").sort((a,b)=>(b.Alcance||0)-(a.Alcance||0)).filter(r=>{const k=r.Autor+r.Contenido;if(seen1.has(k))return false;seen1.add(k);return true}).slice(0,5).map(r=>({autor:r.Autor,contenido:r.Contenido||"",link:r.Link||"",fuente:r.Fuente,alcance:r.Alcance||0}));
  const seen2=new Set<string>();const tn=f.filter(r=>r.Sentimiento==="Negativo").sort((a,b)=>(b.Alcance||0)-(a.Alcance||0)).filter(r=>{const k=r.Autor+r.Contenido;if(seen2.has(k))return false;seen2.add(k);return true}).slice(0,5).map(r=>({autor:r.Autor,contenido:r.Contenido||"",link:r.Link||"",fuente:r.Fuente,alcance:r.Alcance||0}));
  const fc=[...f];
  const t5ag=fc.sort((a,b)=>(b.Alcance||0)-(a.Alcance||0)).slice(0,5).map(r=>({nombre:r.Autor,valor:r.Alcance||0,link:r.Link||"",fuente:r.Fuente,titulo:r.Contenido?.substring(0,80)||""}));
  const fc2=[...f];
  const t5cg=fc2.sort((a,b)=>(b.AVE||0)-(a.AVE||0)).slice(0,5).map(r=>({nombre:r.Autor,valor:r.AVE||0,link:r.Link||"",fuente:r.Fuente,titulo:r.Contenido?.substring(0,80)||""}));
  const t5af:Record<string,Top5Item[]>={};const t5cf:Record<string,Top5Item[]>={};
  VS.forEach(s=>{const sub=[...f.filter(r=>r.Fuente===s)];t5af[s]=sub.sort((a,b)=>(b.Alcance||0)-(a.Alcance||0)).slice(0,5).map(r=>({nombre:r.Autor,valor:r.Alcance||0,link:r.Link||"",fuente:r.Fuente,titulo:r.Contenido?.substring(0,80)||""}));const sub2=[...f.filter(r=>r.Fuente===s)];t5cf[s]=sub2.sort((a,b)=>(b.AVE||0)-(a.AVE||0)).slice(0,5).map(r=>({nombre:r.Autor,valor:r.AVE||0,link:r.Link||"",fuente:r.Fuente,titulo:r.Contenido?.substring(0,80)||""}))});
  const hm:Record<number,number>={};f.forEach(r=>{const h=r.Hora;if(h>=0&&h<=23)hm[h]=(hm[h]||0)+1});
  const hd=Array.from({length:24},(_,i)=>({hora:i,total:hm[i]||0}));
  return{dataType:"social",totalMenciones:n,totalAlcance:alc,totalInteracciones:inter,autoresUnicos:uniq,totalCosto:costT,sentCounts:sc,sentNeto:sn,trendData:td,fuenteData:fd,kpiByFuente:kf,topPositivas:tp,topNegativas:tn,rawRows:f,top5AlcGeneral:t5ag,top5CostGeneral:t5cg,top5AlcPorFuente:t5af,top5CostPorFuente:t5cf,hourData:hd,tierData:[],tipoNotaData:[],estadoData:[],top5Medios:[]};
}
function processMedia(rows:MediaRow[]):PData{
  const f=rows.filter(r=>VM.includes(r.TipoMedio));const n=f.length;
  const alc=f.reduce((s,r)=>s+(r.Alcance||0),0);
  const costT=f.reduce((s,r)=>s+(r.Costo||0),0);
  const uniq=new Set(f.map(r=>r.Medio)).size;
  const sc={Positivo:0,Negativo:0,Neutro:0};
  f.forEach(r=>{if(r.Sentimiento==="Positivo")sc.Positivo++;if(r.Sentimiento==="Negativo")sc.Negativo++;if(r.Sentimiento==="Neutro")sc.Neutro++});
  const sn=n>0?((sc.Positivo-sc.Negativo)/n)*100:0;
  const dm:Record<string,TrendRow>={};
  f.forEach(r=>{const d=r.Fecha?.substring(0,10);if(!d)return;if(!dm[d]){const e:TrendRow={date:d,total:0,Positivo:0,Negativo:0,Neutro:0};VM.forEach(t=>{e[t]=0});dm[d]=e}dm[d].total++;if(r.Sentimiento==="Positivo"||r.Sentimiento==="Negativo"||r.Sentimiento==="Neutro")(dm[d][r.Sentimiento] as number)++;if(VM.includes(r.TipoMedio))(dm[d][r.TipoMedio] as number)++});
  const td=Object.values(dm).sort((a,b)=>a.date.localeCompare(b.date));
  const fm:Record<string,FuenteRow>={};
  f.forEach(r=>{const k=r.TipoMedio;if(!fm[k])fm[k]={fuente:k,Positivo:0,Negativo:0,Neutro:0,total:0};fm[k].total++;if(r.Sentimiento==="Positivo")fm[k].Positivo++;if(r.Sentimiento==="Negativo")fm[k].Negativo++;if(r.Sentimiento==="Neutro")fm[k].Neutro++});
  const fd=Object.values(fm).sort((a,b)=>{const ia=VM.indexOf(a.fuente);const ib=VM.indexOf(b.fuente);return ia-ib});
  const km:Record<string,{fuente:string;menciones:number;impresiones:number;costo:number;autores:Set<string>}>={};
  f.forEach(r=>{const k=r.TipoMedio;if(!km[k])km[k]={fuente:k,menciones:0,impresiones:0,costo:0,autores:new Set()};km[k].menciones++;km[k].impresiones+=r.Alcance||0;km[k].costo+=r.Costo||0;km[k].autores.add(r.Medio)});
  const kf=Object.values(km).map(k=>({fuente:k.fuente,menciones:k.menciones,interacciones:0,impresiones:k.impresiones,lideres:k.autores.size,costo:k.costo})).sort((a,b)=>{const ia=VM.indexOf(a.fuente);const ib=VM.indexOf(b.fuente);return ia-ib});
  const seen1=new Set<string>();const tp=f.filter(r=>r.Sentimiento==="Positivo").sort((a,b)=>(b.Alcance||0)-(a.Alcance||0)).filter(r=>{const k=r.Medio+r.Titulo;if(seen1.has(k))return false;seen1.add(k);return true}).slice(0,5).map(r=>({autor:r.Medio,contenido:r.Titulo||(r.Texto?r.Texto.substring(0,200):""),link:r.Link||"",fuente:r.TipoMedio,alcance:r.Alcance||0}));
  const seen2=new Set<string>();const tn=f.filter(r=>r.Sentimiento==="Negativo").sort((a,b)=>(b.Alcance||0)-(a.Alcance||0)).filter(r=>{const k=r.Medio+r.Titulo;if(seen2.has(k))return false;seen2.add(k);return true}).slice(0,5).map(r=>({autor:r.Medio,contenido:r.Titulo||(r.Texto?r.Texto.substring(0,200):""),link:r.Link||"",fuente:r.TipoMedio,alcance:r.Alcance||0}));
  const fc=[...f];const t5ag=fc.sort((a,b)=>(b.Alcance||0)-(a.Alcance||0)).slice(0,5).map(r=>({nombre:r.Medio,valor:r.Alcance||0,link:r.Link||"",fuente:r.TipoMedio,titulo:r.Titulo||""}));
  const fc2=[...f];const t5cg=fc2.sort((a,b)=>(b.Costo||0)-(a.Costo||0)).slice(0,5).map(r=>({nombre:r.Medio,valor:r.Costo||0,link:r.Link||"",fuente:r.TipoMedio,titulo:r.Titulo||""}));
  const t5af:Record<string,Top5Item[]>={};const t5cf:Record<string,Top5Item[]>={};
  VM.forEach(t=>{const sub=[...f.filter(r=>r.TipoMedio===t)];t5af[t]=sub.sort((a,b)=>(b.Alcance||0)-(a.Alcance||0)).slice(0,5).map(r=>({nombre:r.Medio,valor:r.Alcance||0,link:r.Link||"",fuente:r.TipoMedio,titulo:r.Titulo||""}));const sub2=[...f.filter(r=>r.TipoMedio===t)];t5cf[t]=sub2.sort((a,b)=>(b.Costo||0)-(a.Costo||0)).slice(0,5).map(r=>({nombre:r.Medio,valor:r.Costo||0,link:r.Link||"",fuente:r.TipoMedio,titulo:r.Titulo||""}))});
  const tm:Record<string,number>={};f.forEach(r=>{const t=r.Tier||"Sin Tier";tm[t]=(tm[t]||0)+1});
  const tierOrder=["Tier 1","Tier 2","Tier 3"];const tierD=tierOrder.filter(t=>tm[t]).map(t=>({name:t,value:tm[t]||0}));Object.entries(tm).forEach(([k,v])=>{if(!tierOrder.includes(k))tierD.push({name:k,value:v})});
  const tnm:Record<string,number>={};f.forEach(r=>{const t=r.TipoNota||"Sin tipo";tnm[t]=(tnm[t]||0)+1});
  const tnD=Object.entries(tnm).map(([k,v])=>({name:k,value:v})).sort((a,b)=>b.value-a.value);
  const em:Record<string,number>={};f.forEach(r=>{const e=r.Estado||"Sin estado";em[e]=(em[e]||0)+1});
  const eD=Object.entries(em).map(([k,v])=>({name:k,value:v})).sort((a,b)=>b.value-a.value);
  const mm:Record<string,number>={};f.forEach(r=>{mm[r.Medio]=(mm[r.Medio]||0)+1});
  const t5m=Object.entries(mm).map(([k,v])=>({nombre:k,total:v})).sort((a,b)=>b.total-a.total).slice(0,5);
  return{dataType:"media",totalMenciones:n,totalAlcance:alc,totalInteracciones:0,autoresUnicos:uniq,totalCosto:costT,sentCounts:sc,sentNeto:sn,trendData:td,fuenteData:fd,kpiByFuente:kf,topPositivas:tp,topNegativas:tn,rawRows:f,top5AlcGeneral:t5ag,top5CostGeneral:t5cg,top5AlcPorFuente:t5af,top5CostPorFuente:t5cf,hourData:[],tierData:tierD,tipoNotaData:tnD,estadoData:eD,top5Medios:t5m};
}
function processFusionado(sp:PData,mp:PData):PData{
  const n=sp.totalMenciones+mp.totalMenciones;const alc=sp.totalAlcance+mp.totalAlcance;
  const inter=sp.totalInteracciones;const costT=sp.totalCosto+mp.totalCosto;
  const uniq=sp.autoresUnicos+mp.autoresUnicos;
  const sc={Positivo:sp.sentCounts.Positivo+mp.sentCounts.Positivo,Negativo:sp.sentCounts.Negativo+mp.sentCounts.Negativo,Neutro:sp.sentCounts.Neutro+mp.sentCounts.Neutro};
  const sn=n>0?((sc.Positivo-sc.Negativo)/n)*100:0;
  /* Merge fuente data */
  const fd=[...sp.fuenteData,...mp.fuenteData];
  const kf=[...sp.kpiByFuente,...mp.kpiByFuente];
  /* Merge trend data */
  const tdm:Record<string,TrendRow>={};
  const allKeys=[...VS,...VM,"total","Positivo","Negativo","Neutro"];
  [...sp.trendData,...mp.trendData].forEach(r=>{const d=r.date;if(!tdm[d]){const e:TrendRow={date:d,total:0,Positivo:0,Negativo:0,Neutro:0};allKeys.forEach(k=>{if(!(k in e))e[k]=0});tdm[d]=e}allKeys.forEach(k=>{if(k in r)(tdm[d][k] as number)+=(r[k] as number)||0})});
  const td=Object.values(tdm).sort((a,b)=>a.date.localeCompare(b.date));
  /* Merge top5 - combined by cost (AVE+Costo) and alcance */
  const allSoc=(sp.rawRows as SocialRow[]).map(r=>({nombre:r.Autor,valor:r.Alcance||0,costo:r.AVE||0,link:r.Link||"",fuente:r.Fuente,titulo:r.Contenido?.substring(0,80)||""}));
  const allMed=(mp.rawRows as MediaRow[]).map(r=>({nombre:r.Medio,valor:r.Alcance||0,costo:r.Costo||0,link:r.Link||"",fuente:r.TipoMedio,titulo:r.Titulo||""}));
  const combined=[...allSoc,...allMed];
  const t5ag=[...combined].sort((a,b)=>b.valor-a.valor).slice(0,5).map(r=>({nombre:r.nombre,valor:r.valor,link:r.link,fuente:r.fuente,titulo:r.titulo}));
  const t5cg=[...combined].sort((a,b)=>b.costo-a.costo).slice(0,5).map(r=>({nombre:r.nombre,valor:r.costo,link:r.link,fuente:r.fuente,titulo:r.titulo}));
  const t5af={...sp.top5AlcPorFuente,...mp.top5AlcPorFuente};
  const t5cf={...sp.top5CostPorFuente,...mp.top5CostPorFuente};
  return{dataType:"fusionado",totalMenciones:n,totalAlcance:alc,totalInteracciones:inter,autoresUnicos:uniq,totalCosto:costT,sentCounts:sc,sentNeto:sn,trendData:td,fuenteData:fd,kpiByFuente:kf,topPositivas:[...sp.topPositivas.slice(0,5)],topNegativas:[...sp.topNegativas.slice(0,5)],rawRows:[...sp.rawRows,...mp.rawRows],top5AlcGeneral:t5ag,top5CostGeneral:t5cg,top5AlcPorFuente:t5af,top5CostPorFuente:t5cf,hourData:sp.hourData,tierData:mp.tierData,tipoNotaData:mp.tipoNotaData,estadoData:mp.estadoData,top5Medios:mp.top5Medios};
}
function parseNum(v:unknown):number{if(typeof v==="number")return v;if(typeof v==="string"){if(v.startsWith("="))return 0;const c=v.replace(/[$,\s]/g,"");const n=parseFloat(c);return isNaN(n)?0:n}return 0}
function fmt(n:number):string{if(n>=1e6)return(n/1e6).toFixed(1)+"M";if(n>=1e3)return(n/1e3).toFixed(1)+"K";return String(Math.round(n))}
function fmtM(n:number):string{if(n>=1e6)return"$"+(n/1e6).toFixed(1)+"M";if(n>=1e3)return"$"+(n/1e3).toFixed(1)+"K";return"$"+Math.round(n).toLocaleString()}

/* ═══════ EXCEL PARSER ═══════ */
function parseExcel(file:File):Promise<{social:SocialRow[];media:MediaRow[]}>{
  return new Promise((resolve,reject)=>{
    const reader=new FileReader();
    reader.onload=(e)=>{
      try{
        const data=new Uint8Array(e.target?.result as ArrayBuffer);
        const wb=XLSX.read(data,{type:"array"});
        const social:SocialRow[]=[];const media:MediaRow[]=[];
        wb.SheetNames.forEach(name=>{
          const ws=wb.Sheets[name];
          const json=XLSX.utils.sheet_to_json(ws,{raw:true}) as Record<string,unknown>[];
          if(!json.length)return;const cols=Object.keys(json[0]);
          const isMedia=cols.some(c=>c.toLowerCase().includes("tipo de medio")||c.toLowerCase().includes("tier"));
          const isSocialV1=cols.some(c=>c.toLowerCase().includes("plataforma")||c.toLowerCase().includes("me gusta"));
          const isSocialV2=!isMedia&&cols.some(c=>c==="Fuente")&&cols.some(c=>c==="Autor")&&cols.some(c=>c==="Contenido");
          const isSocial=isSocialV1||isSocialV2;
          if(isMedia&&!isSocial){
            json.forEach(row=>{
              const mf=row["Fecha"];let mfs="";
              if(typeof mf==="number"){const dd=XLSX.SSF.parse_date_code(mf);mfs=dd.y+"-"+String(dd.m).padStart(2,"0")+"-"+String(dd.d).padStart(2,"0")}else if(mf instanceof Date){mfs=mf.toISOString().substring(0,10)}else{mfs=String(mf||"").substring(0,10)}
              let costo=parseNum(row["Costo"]);
              if(costo===0){const ref=XLSX.utils.encode_cell({r:json.indexOf(row)+1,c:17});const cell=ws[ref];if(cell)costo=parseNum(cell.v)}
              media.push({Titulo:String(row["Titulo"]||row["Título"]||""),Texto:String(row["Texto"]||""),Autor:String(row["Autor"]||""),Fecha:mfs,Medio:String(row["Nombre del Medio"]||""),TipoMedio:String(row["Tipo de Medio"]||""),Sentimiento:String(row["Sentimiento"]||""),Alcance:Number(row["Alcance"]||0),Tier:String(row["Tier"]||""),Costo:costo,Link:String(row["Link de Nota"]||row["Link URL Medio"]||""),TipoNota:String(row["Tipo de Nota"]||""),Estado:String(row["Estado"]||"")})
            });
          }else if(isSocial){
            json.forEach((row,ri)=>{
              const ff=row["Fecha"];let fs="";let hora=0;
              if(typeof ff==="number"){const dd=XLSX.SSF.parse_date_code(ff);fs=dd.y+"-"+String(dd.m).padStart(2,"0")+"-"+String(dd.d).padStart(2,"0");hora=dd.H||0}
              else if(typeof ff==="string"){fs=ff.substring(0,10);const hm=ff.match(/(\d{1,2}):\d{2}/);if(hm)hora=parseInt(hm[1])}
              else{fs=String(ff||"").substring(0,10)}
              /* Try Hora column override */
              const rawHora=row["Hora"];
              if(rawHora!==undefined&&rawHora!==null){
                if(typeof rawHora==="number"){
                  if(rawHora>1000){const hd=XLSX.SSF.parse_date_code(rawHora);hora=hd.H||0}
                  else if(rawHora>=0&&rawHora<1){hora=Math.round(rawHora*24)%24}
                  else{hora=Math.floor(rawHora)%24}
                }else if(rawHora instanceof Date){hora=rawHora.getHours()}
                else if(typeof rawHora==="string"){const hp=rawHora.match(/(\d{1,2}):/);if(hp)hora=parseInt(hp[1])}
              }
              let ave=parseNum(row["AVE"]);
              if(ave===0){const cellRef="Q"+(ri+2);const cell=ws[cellRef];if(cell&&typeof cell.v==="number")ave=cell.v}
              if(ave===0){const seg=parseNum(row["Seguidores del Autor"]);let cpm=parseNum(row["CPM (MXN)"]);if(cpm===0){const cpmRef="N"+(ri+2);const cpmCell=ws[cpmRef];if(cpmCell&&typeof cpmCell.v==="number")cpm=cpmCell.v}if(seg>0&&cpm>0)ave=(seg*0.1/1000)*cpm}
              social.push({Fecha:fs,Fuente:String(row["Plataforma"]||row["Fuente"]||""),Autor:String(row["Usuario"]||row["Autor"]||""),Sentimiento:String(row["Sentimiento (Red Social)"]||row["Sentimiento"]||""),Alcance:Number(row["Seguidores del Autor"]||row["Alcance"]||0),Likes:Number(row["Me Gusta / Likes"]||row["Likes"]||0),Comentarios:Number(row["Comentarios"]||0),Compartidos:Number(row["Compartidos"]||0),Contenido:String(row["Contenido"]||""),Link:String(row["Link URL Medio"]||row["URL"]||""),Seguidores:Number(row["Seguidores del Autor"]||0),AVE:ave,Hora:hora})
            });
          }
        });
        resolve({social,media});
      }catch(err){reject(err)}
    };
    reader.onerror=reject;reader.readAsArrayBuffer(file);
  });
}

/* ═══════ AI TEXTS ═══════ */
function aiResumen(d:PData):string{const t=d.dataType==="social"?"publicaciones en redes sociales":"notas en medios tradicionales";const pp=d.totalMenciones>0?((d.sentCounts.Positivo/d.totalMenciones)*100).toFixed(0):"0";const np=d.totalMenciones>0?((d.sentCounts.Negativo/d.totalMenciones)*100).toFixed(0):"0";const up=d.totalMenciones>0?((d.sentCounts.Neutro/d.totalMenciones)*100).toFixed(0):"0";const tf=d.fuenteData[0];return"Durante el periodo se registraron "+d.totalMenciones+" "+t+" con alcance de "+fmt(d.totalAlcance)+" impresiones"+(d.dataType==="social"?" y "+fmt(d.totalInteracciones)+" interacciones":" y un costo estimado de "+fmtM(d.totalCosto))+". Sentimiento: "+pp+"% positivo, "+np+"% negativo y "+up+"% neutro (Neto: "+d.sentNeto.toFixed(1)+"%). "+(tf?tf.fuente+" concentra "+tf.total+" menciones.":"")+" Se identificaron "+d.autoresUnicos+" "+(d.dataType==="social"?"autores":"medios")+"."}
function aiPicos(d:PData):string{if(!d.trendData.length)return"Sin datos suficientes.";const mx=d.trendData.reduce((m,x)=>x.total>m.total?x:m,d.trendData[0]);return"Pico máximo el "+mx.date+" con "+mx.total+" "+(d.dataType==="social"?"publicaciones":"notas")+", sugiriendo un evento detonador."}
function aiSent(d:PData):string{const dom=d.sentCounts.Positivo>d.sentCounts.Negativo?"positivo":d.sentCounts.Negativo>d.sentCounts.Positivo?"negativo":"equilibrado";return"Sentimiento "+dom+" predomina. "+(dom==="positivo"?"Recepción favorable; monitorear menciones negativas.":dom==="negativo"?"Requiere atención en estrategia de comunicación.":"Conversación polarizada; monitoreo constante.")+" Sentimiento Neto: "+d.sentNeto.toFixed(1)+"%.";}
function aiFuentes(d:PData):string{const t=d.fuenteData[0];if(!t)return"";return t.fuente+" lidera con "+t.total+" menciones ("+(d.totalMenciones>0?((t.total/d.totalMenciones)*100).toFixed(0):"0")+"%). "+(d.fuenteData.length>1?"Seguido por "+d.fuenteData[1].fuente+" con "+d.fuenteData[1].total+".":"")}
function aiTendSent(d:PData):string{if(!d.trendData.length)return"";const l=d.trendData[d.trendData.length-1];const ff=d.trendData[0];return"Evolución: "+(l.Positivo>ff.Positivo?"tendencia ascendente en positivas":"estabilidad en positivas")+". "+(l.Negativo>ff.Negativo?"Negativas en incremento.":"Negativas estables o en descenso.")}
function aiTemas(d:PData,aiTexts:Record<string,string>):{tema:string;detalle:string;link:string}[]{
  if(aiTexts.temas){try{const s=aiTexts.temas.replace(/[\x00-\x1f]/g,c=>c==="\n"?"\\n":"");const parsed=JSON.parse(s);return parsed.map((t:{tema:string;detalle:string})=>({tema:String(t.tema||""),detalle:String(t.detalle||""),link:""}))}catch(e){console.error("Temas parse error:",e)}}
  const links=d.rawRows.map(r=>"Link" in r?(r as SocialRow).Link||(r as MediaRow).Link||"":"").filter(Boolean);
  return[{tema:"Temática principal",detalle:"De "+d.totalMenciones+" menciones, la mayoría gira en torno al tema central monitoreado.",link:links[0]||""},{tema:"Narrativa secundaria",detalle:"Conversación complementaria que agrega contexto o debate adicional.",link:links[1]||""},{tema:"Aspectos operativos",detalle:"Parte de la audiencia se enfoca en aspectos prácticos y logísticos.",link:links[2]||""}]
}
function aiHora(d:PData):string{if(!d.hourData.length)return"";const mx=d.hourData.reduce((m,x)=>x.total>m.total?x:m,d.hourData[0]);return"La mayor actividad se concentra a las "+mx.hora+":00 hrs con "+mx.total+" publicaciones. Se recomienda programar contenido en horarios de alta actividad."}
function aiTier(d:PData):string{const t=d.tierData[0];if(!t)return"";return"El nivel más frecuente es "+t.name+" con "+t.value+" notas ("+(d.totalMenciones>0?((t.value/d.totalMenciones)*100).toFixed(0):"0")+"%). La distribución por tier permite evaluar la calidad de la cobertura."}
function aiTop5Med(d:PData):string{const t=d.top5Medios[0];if(!t)return"";return t.nombre+" lidera con "+t.total+" notas. La concentración en pocos medios puede indicar relaciones editoriales sólidas."}
function aiTipoNota(d:PData):string{const t=d.tipoNotaData[0];if(!t)return"";return"El tipo predominante es "+t.name+" con "+t.value+" apariciones. Esto refleja el tratamiento editorial del tema."}
function aiEstado(d:PData):string{const t=d.estadoData[0];if(!t)return"";return t.name+" concentra la mayor cobertura con "+t.value+" notas. La distribución geográfica es clave para estrategias regionales."}
function aiConc(d:PData):string{return"El monitoreo revela "+d.totalMenciones+" menciones con sentimiento neto de "+d.sentNeto.toFixed(1)+"%. "+(d.sentNeto>0?"La percepción es favorable, oportunidad para fortalecer posicionamiento.":"Se detectan áreas de oportunidad para mejorar la percepción.")+" Se recomienda mantener monitoreo continuo."}
function aiRec(d:PData):string{const r:string[]=[];if(d.sentCounts.Negativo>d.sentCounts.Positivo)r.push("Implementar estrategia de gestión de crisis.");else r.push("Capitalizar el sentimiento positivo amplificando mensajes clave.");if(d.fuenteData.length>1)r.push("Diversificar presencia en "+d.fuenteData[d.fuenteData.length-1].fuente+".");r.push("Monitorear en tiempo real los picos de conversación.");r.push("Desarrollar contenido estratégico alineado a los temas clave.");return r.join(" ")}
function aiTopPub():string{return"Los rankings por alcance y costo permiten identificar las publicaciones y medios con mayor impacto. Se recomienda fortalecer relaciones con los de mayor alcance."}

