const DB:Brand={name:"GDP Monitoreo",primaryColor:"#1a1a2e",secondaryColor:"#16213e",accentColor:"#0f3460",positiveColor:"#10b981",negativeColor:"#ef4444",neutralColor:"#94a3b8",chartColors:["#3b82f6","#8b5cf6","#f59e0b","#ec4899","#14b8a6","#f97316","#06b6d4"],titleFont:"'Outfit', sans-serif",bodyFont:"'DM Sans', sans-serif",mediaColors:{"Periódico":"#377eb8",Internet:"#e41a1b",Radio:"#ffcd00","Televisión":"#4eaf4a",Revista:"#7f7f7f"},tierColors:{"Tier 1":"#d5bc1a","Tier 2":"#8e9db1","Tier 3":"#9c6f44"},top5MedColor:"#8b5cf6",bannerPrimary:"#1a1a2e",bannerSecondary:"#16213e",titleTextColor:"#ffffff",aiBlockColor:"blue"};
function genPalette(c1:string,c2:string,n:number):string[]{
  const base=["#e63946","#457b9d","#2a9d8f","#e9c46a","#f4a261","#264653","#6a4c93","#1982c4","#8ac926","#ff595e","#6d6875","#0077b6","#d62828","#fcbf49","#43aa8b"];
  const hex=(s:string)=>parseInt(s,16);
  const r1=hex(c1.slice(1,3)),g1=hex(c1.slice(3,5)),b1=hex(c1.slice(5,7));
  const r2=hex(c2.slice(1,3)),g2=hex(c2.slice(3,5)),b2=hex(c2.slice(5,7));
  const res:string[]=[c1,c2];
  for(const b of base){if(res.length>=n)break;const rb=hex(b.slice(1,3)),gb=hex(b.slice(3,5)),bb=hex(b.slice(5,7));const d1=Math.abs(rb-r1)+Math.abs(gb-g1)+Math.abs(bb-b1);const d2=Math.abs(rb-r2)+Math.abs(gb-g2)+Math.abs(bb-b2);if(d1>80&&d2>80&&!res.includes(b))res.push(b)}
  while(res.length<n){const i=res.length;res.push(base[i%base.length])}
  return res.slice(0,n);
}

/* ═══════ COMPONENTS ═══════ */
function KPI({title,value,icon,color,brand}:{title:string;value:string|number;icon:React.ReactNode;color:string;brand:Brand}){return(<div className="bg-white rounded-2xl p-4 border border-gray-100 flex-1 min-w-[140px]" style={{boxShadow:"0 1px 3px rgba(0,0,0,0.06)"}}><div className="flex justify-between items-center mb-1.5"><span className="text-[10px] text-gray-400 font-medium">{title}</span><div className="w-7 h-7 rounded-lg flex items-center justify-center" style={{background:color+"18"}}>{icon}</div></div><div className="text-2xl font-bold" style={{color:brand.primaryColor,fontFamily:brand.titleFont}}>{value}</div></div>)}
function Donut({data,brand,title}:{data:{Positivo:number;Negativo:number;Neutro:number};brand:Brand;title?:string}){
  const total=data.Positivo+data.Negativo+data.Neutro;if(total===0)return null;
  const cd=[{name:"Positivo",value:data.Positivo,color:brand.positiveColor},{name:"Negativo",value:data.Negativo,color:brand.negativeColor},{name:"Neutro",value:data.Neutro,color:brand.neutralColor}];
  const sz=160;
  return(<div className="flex flex-col items-center">{title&&<div className="text-xs font-bold text-gray-700 mb-1.5">{title}</div>}<div style={{position:"relative",width:sz,height:sz}}><PieChart width={sz} height={sz} margin={{top:0,right:0,bottom:0,left:0}}><Pie data={cd} cx="50%" cy="50%" innerRadius={35} outerRadius={68} paddingAngle={3} dataKey="value" stroke="none">{cd.map((e,i)=><Cell key={i} fill={e.color}/>)}</Pie></PieChart><div style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",pointerEvents:"none"}}><span style={{fontSize:18,fontWeight:700,color:"#1a1a2e",lineHeight:1}}>{total}</span><span style={{fontSize:9,color:"#94a3b8",marginTop:2}}>notas</span></div></div><div className="flex gap-2 mt-1.5">{cd.map((item,i)=>(<div key={i} className="flex items-center gap-1"><div className="w-2 h-2 rounded-sm" style={{background:item.color}}/><span className="text-[10px] font-bold" style={{color:item.color}}>{item.value} ({((item.value/total)*100).toFixed(0)}%)</span></div>))}</div></div>);
}
function DonutGrid({items,brand}:{items:FuenteRow[];brand:Brand}){
  if(items.length===0)return null;
  const D=(f:FuenteRow,i:number)=><Donut key={i} data={{Positivo:f.Positivo,Negativo:f.Negativo,Neutro:f.Neutro}} brand={brand} title={f.fuente}/>;
  const Row=(arr:FuenteRow[],off:number)=><div className="flex gap-4 justify-center mb-4">{arr.map((f,i)=>D(f,off+i))}</div>;
  const n=items.length;
  if(n<=5)return<div className="flex flex-wrap gap-4 justify-center">{items.map((f,i)=>D(f,i))}</div>;
  let rows:number[];
  if(n===6)rows=[3,3];else if(n===7)rows=[4,3];else if(n===8)rows=[4,4];else if(n===9)rows=[3,3,3];else if(n===10)rows=[5,5];else{rows=[];let r=n;while(r>0){const c=Math.min(r,5);rows.push(c);r-=c}}
  let off=0;
  return<div>{rows.map((c,ri)=>{const slice=items.slice(off,off+c);off+=c;return<div key={ri}>{Row(slice,off-c)}</div>})}</div>;
}
const AI_COLORS:Record<string,string>={blue:"linear-gradient(135deg,#f0f9ff 0%,#f5f3ff 100%)",purple:"linear-gradient(135deg,#f5f3ff 0%,#fdf4ff 100%)",green:"linear-gradient(135deg,#f0fdf4 0%,#f0f9ff 100%)",amber:"linear-gradient(135deg,#fffbeb 0%,#fefce8 100%)",gray:"linear-gradient(135deg,#f9fafb 0%,#f3f4f6 100%)",rose:"linear-gradient(135deg,#fff1f2 0%,#fdf2f8 100%)"};
function AIBlock({text,brand,loading}:{text:string;brand:Brand;loading:boolean}){
  const safeText=typeof text==="string"?text:String(text||"");
  const renderPart=(t:string)=>{
    const st=typeof t==="string"?t:String(t||"");
    /* Split by ***bold+italic***, **bold**, and [Ver fuente](url) */
    const segs=st.split(/(\*\*\*[^*]+\*\*\*|\*\*[^*]+\*\*|\[Ver fuente\]\([^)]+\))/g);
    return segs.map((seg,i)=>{
      const linkM=seg.match(/\[Ver fuente\]\(([^)]+)\)/);
      if(linkM)return <a key={i} href={linkM[1]} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded text-[10px] font-semibold no-underline ml-1" style={{background:brand.accentColor+"15",color:brand.accentColor}}><ExternalLink size={10}/>Ver fuente</a>;
      const biM=seg.match(/^\*\*\*(.+)\*\*\*$/);
      if(biM)return <strong key={i} className="font-semibold italic" style={{color:brand.accentColor}}>{biM[1]}</strong>;
      const boldM=seg.match(/^\*\*(.+)\*\*$/);
      if(boldM)return <strong key={i} className="font-semibold text-gray-800">{boldM[1]}</strong>;
      return <span key={i}>{seg}</span>;
    });
  };
  const paragraphs=safeText.split(/\s*\|\|\s*/).filter(Boolean);
  const bg=AI_COLORS[brand.aiBlockColor]||AI_COLORS.blue;
  return(<div className="rounded-xl p-4" style={{background:bg,borderLeft:"4px solid "+brand.accentColor}}><div className="flex items-center gap-1.5 mb-2"><Sparkles size={13} color={brand.accentColor}/><span className="text-[10px] font-semibold uppercase tracking-wider" style={{color:brand.accentColor}}>Análisis IA</span></div>{loading?<div className="flex gap-1.5 py-2">{[0,1,2].map(i=><div key={i} className="w-2 h-2 rounded-full" style={{background:brand.accentColor,animation:"pulse 1.2s ease-in-out "+(i*0.2)+"s infinite"}}/>)}</div>:<div className="space-y-2">{paragraphs.map((pg,pi)=><p key={pi} className="text-sm leading-relaxed text-gray-700">{renderPart(pg)}</p>)}</div>}</div>);
}
function Sec({title,icon,children,brand}:{title:string;icon:React.ReactNode;children:React.ReactNode;brand:Brand}){return(<div className="bg-white rounded-2xl p-6 border border-gray-100 overflow-hidden" style={{boxShadow:"0 1px 3px rgba(0,0,0,0.04)"}}><div className="flex items-center gap-2.5 mb-5"><div className="w-9 h-9 rounded-lg flex items-center justify-center" style={{background:brand.accentColor+"12"}}>{icon}</div><h2 className="text-base font-bold" style={{color:brand.primaryColor,fontFamily:brand.titleFont}}>{title}</h2></div>{children}</div>)}
function MenCard({autor,contenido,link,fuente,alcance,brand,tipo}:{autor:string;contenido:string;link:string;fuente:string;alcance:number;brand:Brand;tipo:"positivo"|"negativo"}){const c=tipo==="positivo"?brand.positiveColor:brand.negativeColor;return(<div className="rounded-xl p-3.5 border h-full" style={{borderColor:c+"30",background:c+"06"}}><div className="flex justify-between items-start mb-1.5"><div className="flex items-center gap-1.5">{tipo==="positivo"?<ThumbsUp size={12} color={c}/>:<ThumbsDown size={12} color={c}/>}<span className="text-xs font-bold text-gray-800">{autor}</span></div><span className="text-[9px] px-2 py-0.5 rounded-full font-medium flex-shrink-0" style={{background:c+"18",color:c}}>{fuente}</span></div><p className="text-[11px] text-gray-600 leading-relaxed mb-1.5">{contenido.substring(0,200)}{contenido.length>200?"...":""}</p><div className="flex justify-between items-center mt-auto">{link&&link!=="undefined"&&<a href={link} target="_blank" rel="noopener noreferrer" className="text-[10px] font-semibold" style={{color:brand.accentColor}}>Ver original</a>}<span className="text-[9px] text-gray-400">{fmt(alcance)} alcance</span></div></div>)}
function T5Table({items,label,brand,showTitulo}:{items:Top5Item[];label:string;brand:Brand;showTitulo?:boolean}){
  if(!items.length)return<p className="text-xs text-gray-400">Sin datos</p>;
  return(<div className="overflow-hidden rounded-lg border border-gray-100"><table className="w-full text-xs"><thead><tr className="bg-gray-50"><th className="text-left px-3 py-2 text-gray-500 font-semibold w-8">#</th><th className="text-left px-3 py-2 text-gray-500 font-semibold">Nombre</th><th className="text-right px-3 py-2 text-gray-500 font-semibold w-20">{label}</th><th className="text-center px-3 py-2 text-gray-500 font-semibold w-12">Link</th></tr></thead><tbody>{items.map((it,i)=>(<tr key={i} className="border-t border-gray-50"><td className="px-3 py-2 font-bold text-gray-700 align-top">{i+1}</td><td className="px-3 py-2 text-gray-700 align-top"><div className="font-semibold truncate max-w-[200px]">{it.nombre}</div>{showTitulo&&it.titulo&&<div className="text-[10px] text-gray-400 mt-0.5 leading-snug" style={{display:"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical",overflow:"hidden"}}>{it.titulo}</div>}</td><td className="px-3 py-2 text-right font-bold align-top" style={{color:brand.accentColor}}>{label==="Costo"||label==="AVE"?fmtM(it.valor):fmt(it.valor)}</td><td className="px-3 py-2 text-center align-top">{it.link&&it.link!=="undefined"?<a href={it.link} target="_blank" rel="noopener noreferrer" className="text-[10px]" style={{color:brand.accentColor}}>Ver</a>:<span className="text-gray-300">—</span>}</td></tr>))}</tbody></table></div>);
}
function CInput({label,value,onChange}:{label:string;value:string;onChange:(v:string)=>void}){return(<div className="flex items-center gap-2"><input type="color" value={value} onChange={e=>onChange(e.target.value)} className="w-8 h-8 border-2 border-gray-200 rounded-md cursor-pointer p-0"/><div><div className="text-[11px] font-medium text-gray-500">{label}</div><div className="text-[9px] text-gray-400 font-mono">{value}</div></div></div>)}
function GenChart({data,brand,colors,vertical}:{data:{name:string;value:number}[];brand:Brand;colors?:string[];vertical?:boolean}){
  if(!data.length)return<p className="text-xs text-gray-400">Sin datos</p>;
  const cls=colors||genPalette(brand.primaryColor,brand.secondaryColor,data.length);
  const isVert=vertical===false;
  if(isVert)return(<ResponsiveContainer width="100%" height={300}><BarChart data={data} margin={{top:20,right:20,left:20,bottom:40}}><CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0"/><XAxis dataKey="name" tick={{fontSize:10,fill:"#64748b"}} interval={0} angle={0} textAnchor="middle" height={50}/><YAxis tick={{fontSize:11,fill:"#94a3b8"}} allowDecimals={false}/><Tooltip/><Bar dataKey="value" radius={[6,6,0,0]} name="Total" label={{position:"top",fill:"#64748b",fontSize:11,fontWeight:700}}>{data.map((_,i)=><Cell key={i} fill={cls[i%cls.length]}/>)}</Bar></BarChart></ResponsiveContainer>);
  return(<ResponsiveContainer width="100%" height={Math.max(220,data.length*28)}><BarChart data={data} layout="vertical" margin={{top:5,right:40,left:10,bottom:5}}><CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0"/><XAxis type="number" tick={{fontSize:11,fill:"#94a3b8"}} allowDecimals={false}/><YAxis type="category" dataKey="name" tick={{fontSize:11,fill:"#64748b"}} width={120}/><Tooltip/><Bar dataKey="value" radius={[0,6,6,0]} name="Total" label={{position:"right",fill:"#64748b",fontSize:11,fontWeight:700}}>{data.map((_,i)=><Cell key={i} fill={cls[i%cls.length]}/>)}</Bar></BarChart></ResponsiveContainer>);
}

