const AI_LENGTHS={resumen:"3-4 párrafos",sentimiento:"2-3 párrafos",temas:"3-5 insights",conclusiones:"2-3 párrafos",recomendaciones:"4-5 recomendaciones",picos:"2-3 párrafos",tendSent:"2-3 párrafos"};
