  const[titleAlign,setTitleAlign]=useState<"left"|"center"|"right">("left");
  const[logoSize,setLogoSize]=useState(48);
  const[socEnabled,setSocEnabled]=useState<Record<string,boolean>>(()=>{const m:Record<string,boolean>={};SOC_SECS.forEach(s=>m[s]=true);return m});
  const[medEnabled,setMedEnabled]=useState<Record<string,boolean>>(()=>{const m:Record<string,boolean>={};MED_SECS.forEach(s=>m[s]=true);return m});
  const[socOrder,setSocOrder]=useState<string[]>(SOC_SECS);
  const[medOrder,setMedOrder]=useState<string[]>(MED_SECS);
  const[fusEnabled,setFusEnabled]=useState<Record<string,boolean>>(()=>{const m:Record<string,boolean>={};FUS_SECS.forEach(s=>m[s]=true);return m});
  const[fusOrder,setFusOrder]=useState<string[]>(FUS_SECS);
  const[sPd,setSPd]=useState<PData|null>(null);
  const[mPd,setMPd]=useState<PData|null>(null);
